mapper.select:
SELECT M.SALES_ID , M.SALES_DATE , M.USER_ID , M.PAYMENT_TYPE , M.SALES_TYPE , M.SALES_STATUS , L.LOCATION_NM , SUM(D.QTY) AS TOTAL_QTY , SUM(D.SALES_PRICE) AS TOTAL_PRICE , (SELECT MAX(NAME) NAME FROM user_mst WHERE USER_ID = (CASE WHEN M.UPDATE_USER IS NOT NULL THEN M.UPDATE_USER ELSE M.CREATE_USER END) ) UPDATE_USER , CASE WHEN P.UPDATE_DATE IS NOT NULL THEN DATE_FORMAT(M.UPDATE_DATE, '%Y-%m-%d %H:%i:%S') ELSE DATE_FORMAT(M.CREATE_DATE, '%Y-%m-%d %H:%i:%S') END UPDATE_DATE FROM sales_mst M LEFT JOIN sales_dtl D ON M.SALES_ID = D.SALES_ID LEFT JOIN product_dtl P ON D.PRODUCT_DTL_ID = P.PRODUCT_DTL_ID LEFT JOIN store_location_mst L ON P.LOCATION_ID = L.LOCATION_ID WHERE 1=1 AND L.LOCATION_ID = #{locationId}
AND M.SALES_DATE >= STR_TO_DATE(#{startDate}, '%Y-%m-%d %H:%i:%s')
AND M.SALES_DATE <= STR_TO_DATE(CONCAT(#{endDate},' 23:59:59'), '%Y-%m-%d %H:%i:%s')
AND M.USER_ID LIKE CONCAT('%',#{userId},'%')
AND M.PAYMENT_TYPE = #{paymentType}
AND M.SALES_STATUS = #{salesStatus}
AND M.SALES_TYPE = #{salesType}
GROUP BY M.SALES_ID ,M.SALES_DATE ,M.USER_ID ,M.PAYMENT_TYPE ,M.SALES_TYPE ,M.SALES_STATUS ,L.LOCATION_NM ORDER BY M.SALES_DATE DESC

